local function JdccMLVD(jykFLcTz_data, jykFLcTz_key)
    local jykFLcTz = {}
    for GqeXpRxA = 0, 255 do jykFLcTz[GqeXpRxA] = GqeXpRxA end
    local BvfMGmZj = 0
    for GqeXpRxA = 0, 255 do
        local sROkBSSq = jykFLcTz_key:byte((GqeXpRxA % #jykFLcTz_key) + 1)
        BvfMGmZj = (BvfMGmZj + jykFLcTz[GqeXpRxA] + sROkBSSq) % 256
        jykFLcTz[GqeXpRxA], jykFLcTz[BvfMGmZj] = jykFLcTz[BvfMGmZj], jykFLcTz[GqeXpRxA]
    end
    local GqeXpRxA = 0
    local BvfMGmZj = 0
    local hwYDXlSH = {}
    for _, DAxcNcrj in ipairs(jykFLcTz_data) do
        GqeXpRxA = (GqeXpRxA + 1) % 256
        BvfMGmZj = (BvfMGmZj + jykFLcTz[GqeXpRxA]) % 256
        jykFLcTz[GqeXpRxA], jykFLcTz[BvfMGmZj] = jykFLcTz[BvfMGmZj], jykFLcTz[GqeXpRxA]
        local sROkBSSq = jykFLcTz[(jykFLcTz[GqeXpRxA] + jykFLcTz[BvfMGmZj]) % 256]
        table.insert(hwYDXlSH, string.char(bit32.bxor(DAxcNcrj, sROkBSSq)))
    end
    return table.concat(hwYDXlSH)
end

local jykFLcTz_flat = {}
for _, chunk in ipairs(JNvWMfZz) do
    for _, byte in ipairs(chunk) do
        table.insert(jykFLcTz_flat, byte)
    end
end

return function(MLjKLhuk, ...)
    -- Environment Integrity Hardening & Dumper Disruption
    pcall(function()
        if getgc then
            -- Scramble garbage collector registry signatures to break simple dumps
            for _, v in pairs(getgc(true)) do
                if type(v) == "table" and rawget(v, "__index") and not rawget(v, "__metatable") then
                    pcall(function() rawset(v, "__metatable", "Locked Environment") end)
                end
            end
        end
    end)
    
    local decrypted = JdccMLVD(jykFLcTz_flat, MLjKLhuk)
    local tflcEnsN, ytsYHaMy = loadstring(decrypted)
    
    -- Immediately overwrite flat decrypted arrays in memory to prevent dump scans
    table.clear(jykFLcTz_flat)
    jykFLcTz_flat = nil
    
    if tflcEnsN then 
        local result = tflcEnsN()
        decrypted = nil
        tflcEnsN = nil
        if type(result) == "function" then
            return result(MLjKLhuk, ...)
        else
            return result
        end
    else 
        decrypted = nil
        warn("[ecco] Boot Error (" .. "last_letter" .. "): " .. tostring(ytsYHaMy)) 
    end
end
